import React, { Component } from "react";
import "./Simulator.css";

import EventQueue from "./Queues/EventQueue";
import LargeJobQueue from "./Queues/LargeJobQueue";
import SmallJobQueue from "./Queues/SmallJobQueue";
import IOQueue from "./Queues/IOQueue";
import SimHeader from "./Utils/SimHeader";
import FinishedJobQueue from "./Queues/FinishedJobQueue";
//import {Rectangle, Circle, Ellipse, Line, Polyline, CornerBox, Triangle} from 'react-shapes';

//import SchedulerManager from "./implementation/SchedulerManager";

import {SchedulerManager as MySystemManager} from "./implementation/SchedulerManager";

  // var data = [
  //   {type: 'A', arrivalTime: 100, number: 1, memory: 20, runtime: 78},
  //   {type: 'A', arrivalTime: 120, number: 2, memory: 60, runtime: 90},
  //   {type: 'A', arrivalTime: 122, number: 3, memory: 1, runtime: 1}
  // ];

var fileReader;

var manager = new MySystemManager();

fetch('inputFileC.txt')
.then(response => response.text())
.then(function(result) { 
  manager.ReadText(result); 
});

class Simulator extends Component {
  constructor() {
    super();
    this.UseSempahores = true;
    this.render = this.render.bind(this);
    this.getTime = this.getTime.bind(this);
    this.state = {time: '', runfor: 0};

    this.UpdateManager = this.UpdateManager.bind(this);
    this.Run = this.Run.bind(this);
    this.LoadFile = this.LoadFile.bind(this);
    this.ReloadManager = this.ReloadManager.bind(this);
  }

  ReloadManager = (e) => {
    var toggleAlerts = manager.ignorealerts;
    manager = new MySystemManager(toggleAlerts);
    const content = fileReader.result;
    // console.log(content);
    manager.ReadText(content);
    this.UpdateManager(0);
    this.Header.ChangeTime(manager.CurrentTime);
  };

  LoadFile(file) {
    // let file = event.target.files[0];
    // console.log(file);
    fileReader = new FileReader();
    fileReader.onloadend = this.ReloadManager;
    fileReader.readAsText(file);
  
  }

  componentDidMount() {
      this._interval = setInterval(() => this.setState({time: this.getTime()}), 100);
  }
  componentWillUnmount() {
    clearInterval(this._interval);
  }
  getTime(){
    let t = new Date();
    return `${t.getHours()}:${t.getMinutes()}:${t.getSeconds()}`;
  }
  componentDidUpdate() {
    this.UseSempahores = this.Header.GetSemaphoreToggleState();
    // this.Header.TimeChanged(manager.CurrentTime);
    // this.setState(
    // console.log("Updated");
    //console.log(this.Header.GetSemaphoreToggleState());
  }

  UpdateManager(time) {
    if (time>30000) {time=30000;}
    console.log("Resetting Manager");
    // console.log(manager);
    manager.Reset();
    // manager = new SchedulerManager(manager.PermEventListOBJ);
    // console.log(manager);
    manager.Run(time); 
  }

  Run(time) {
    manager.Run(time);
    this.Header.ChangeTime(manager.CurrentTime);
  }
  
  render() {
    const CPU_ELEMENT = manager.CPU.idle ? (
      <div className="column-divider column-A4">
        <div className="LargeTable">
          <h2 className="fixed"><center>CPU</center></h2>
          <div className="CPU">
            <div>
              <br/><br/><br/><br/><br/><br/><br/><br/><br/><br/>
              <h2 className="fixed"><center>IDLE</center></h2>
            </div>
          </div>
        </div>
      </div>
  ) : (
    <div className="column-divider column-A4">
      <div className="LargeTable">
        <h2 className="fixed"><center>CPU</center></h2>
        <div className="CPU">
          <div>
            <br/><br/><br/><br/><br/><br/><br/><br/>
            <h2 className="fixed"><center>{"Job " + manager.CPU.job.JobNumber}</center></h2>
            <h2 className="fixed"><center>{"Memory: " + manager.CPU.job.Memory}</center></h2>
            <h2 className="fixed"><center>{"Runtime: " + manager.CPU.job.RemainingRunTime()}</center></h2>
            <h2 className="fixed"><center>{"Quantum: " + manager.CPU.quantum}</center></h2>
          </div>
        </div>
      </div>
    </div>
  );

  const PCB_ELEMENT = this.UseSempahores ? (
    <div className="column-divider column-B1">
        <div className="SmallTable">
          <h2 className="fixed"><center>Process Control Block</center></h2>
          <SmallJobQueue data={manager.RejectedJobsQueue}/>
        </div>
        <br/>
        <div className="SmallTable">
          <h2 className="fixed"><center>Job Scheduling Queue</center></h2>
          <SmallJobQueue data={manager.IncomingJobsQueue}/>
        </div>
      </div>
) : (
  <div className="column-divider column-B1">  
    <div className="LargeTable">
      <h2 className="fixed"><center>Job Scheduling Queue</center></h2>
      <LargeJobQueue data={manager.IncomingJobsQueue}/>
    </div>
  </div>
);

  const Semaphores = this.UseSempahores ? (
  <div>
    <div className="container">
      <div className="column-divider column-A1">  
        <div className="LargeTable">
          <h2 className="fixed"><center>Incoming Event Queue</center></h2>
          <EventQueue data={manager.EventListOBJ}/>
        </div>              
      </div> 
      <div className="column-divider column-AS1"/> 
      <div className="column-divider column-A2"> 
        <div className="SmallTable">
          <h2 className="fixed"><center>Ready Queue Level 1</center></h2>
          <SmallJobQueue data={manager.ReadyQueueI}/>
        </div>
        <br/>
        <div className="SmallTable">
          <h2 className="fixed"><center>I/O Burst Queue</center></h2>
          <IOQueue data={manager.WaitQueueIO.WaitQueue} Count={3} style={{height: "175px"}}/>
        </div>
      </div>
      <div className="column-divider column-AS2"/> 
      <div className="column-divider column-A3"> 
        <div className="SmallTable">
          <h2 className="fixed"><center>Ready Queue Level 2</center></h2>
          <SmallJobQueue data={manager.ReadyQueueII}/>
        </div>
        <br/>
        <div className="SmallTable">
          <h2 className="fixed"><center>{("Semaphore 1 (Signal: " + manager.S[0] + ")")}</center></h2>
          <SmallJobQueue data={manager.WaitQueueS[0]}/>
        </div>
      </div>
      <div className="column-divider column-AS3"/> 
      {CPU_ELEMENT}
    </div>
    <div className="container">
      {PCB_ELEMENT}
      <div className="column-divider column-BS1"></div>
      <div className="column-divider column-B2">
        <div className="SmallTable">
          <h2 className="fixed"><center>{("Semaphore 2 (Signal: " + manager.S[1] + ")")}</center></h2>
          <SmallJobQueue data={manager.WaitQueueS[1]}/>
        </div>
        <br/>
        <div className="SmallTable">
          <h2 className="fixed"><center>{("Semaphore 4 (Signal: " + manager.S[3] + ")")}</center></h2>
          <SmallJobQueue data={manager.WaitQueueS[3]}/>
        </div>
      </div>
      <div className="column-divider column-BS2"/> 
      <div className="column-divider column-B3"> 
        <div className="SmallTable">
          <h2 className="fixed"><center>{("Semaphore 3 (Signal: " + manager.S[2] + ")")}</center></h2>
          <SmallJobQueue data={manager.WaitQueueS[2]}/>
        </div>
        <br/>
        <div className="SmallTable">
          <h2 className="fixed"><center>{("Semaphore 5 (Signal: " + manager.S[4] + ")")}</center></h2>
          <SmallJobQueue data={manager.WaitQueueS[4]}/>
        </div>
      </div>
      <div className="column-divider column-BS3"></div>
      <div className="column-divider column-B4">
        <div className="LargeTable">
          <h2 className="fixed"><center>Finished Job Queue</center></h2>
          <FinishedJobQueue data={manager.FinishedQueue}/>
        </div>
      </div>
    </div> 
  </div>
    ) : (
  <div>    
    <div className="container">
      <div className="column-divider column-A1">  
        <div className="LargeTable">
          <h2 className="fixed"><center>Incoming Event Queue</center></h2>
          <EventQueue data={manager.EventListOBJ}/>
        </div>              
      </div> 
      <div className="column-divider column-AS1"/>
      <div className="column-divider column-A2">          
        <div className="LargeTable">
          <h2 className="fixed"><center>Ready Queue Level 1</center></h2>
          <LargeJobQueue data={manager.ReadyQueueI}/>
        </div>
      </div>
      <div className="column-divider column-AS2"/> 
      <div className="column-divider column-A3"> 
        <div className="LargeTable">
          <h2 className="fixed"><center>Ready Queue Level 2</center></h2>
          <LargeJobQueue data={manager.ReadyQueueII}/>
        </div>
      </div>
      <div className="column-divider column-AS3"/> 
      {CPU_ELEMENT}
    </div>
    <div className="container">
      {PCB_ELEMENT}
      <div className="column-divider column-BS1"/>
      <div className="column-divider column-B2">
        <div className="LargeTable">
          <h2 className="fixed"><center>I/O Burst Queue</center></h2>
          <IOQueue data={manager.WaitQueueIO.WaitQueue} Count={10} style={{height: "420px"}}/>
        </div>
      </div>
      <div className="column-divider column-BS2"/>
      <div className="column-divider column-B3-B4">
        <div className="SuperLargeTable">
          <h2 className="fixed"><center>Finished Job Queue</center></h2>
          <FinishedJobQueue data={manager.FinishedQueue}/>
        </div>
      </div>
    </div>
  </div>
  );
    return (
        <div>
          <SimHeader ref = {c => this.Header = c}
          UpdateManger={this.UpdateManager}
          Run={this.Run} Time={manager.CurrentTime}
          Reset={this.UpdateManager}
          Memory={manager.FreeMemory}
          ToggleAlerts={manager.ToggleAlerts}/>

          {Semaphores}

          <span>
        <input type="file"
        name="myFile"
        onChange={e => this.LoadFile(e.target.files[0])}
        accept='.txt' />
      </span>

        </div>
    );
  }
}
 
export default Simulator;


